@echo off
echo ========================================
echo HeafitMP Server Stop Script
echo ========================================
echo.

echo Stopping Docker Compose...
docker-compose down

echo.
echo ========================================
echo Stop Complete!
echo ========================================
pause

@echo off
echo ========================================
echo HeafitMP Server Startup Script
echo ========================================
echo.

echo [1/4] Checking Docker service...
docker info >nul 2>&1
if errorlevel 1 (
    echo [ERROR] Docker service is not running. Please start Docker Desktop first.
    pause
    exit /b 1
)
echo [OK] Docker service is running

echo.
echo [2/4] Starting Docker Compose (MySQL + Nacos)...
docker-compose up -d
if errorlevel 1 (
    echo [ERROR] Docker Compose failed to start
    pause
    exit /b 1
)
echo [OK] MySQL and Nacos started

echo.
echo [3/4] Waiting for services to be ready (45 seconds)...
echo Please start the microservices in your IDE:
echo   - HeafitMP-gateway (8080)
echo   - HeafitMP-user-service (8081)
echo   - HeafitMP-device-service (8082)
echo   - HeafitMP-fitting-service (8083)
timeout /t 45 /nobreak >nul

echo.
echo [4/4] Checking service status...
curl -s http://localhost:8848/nacos >nul 2>&1
if errorlevel 1 (
    echo [WARNING] Nacos may not be ready yet. Please visit http://localhost:8848/nacos later
) else (
    echo [OK] Nacos is ready. Please visit http://localhost:8848/nacos
)

echo.
echo ========================================
echo Startup Complete!
echo ========================================
echo.
echo Access URLs:
echo   Nacos: http://localhost:8848/nacos (nacos/nacos)
echo   Gateway: http://localhost:8080
echo.
pause
